// Offline extractor: replays the per-interview extractions already generated by the
// Haiku fan-out (outputs/raw-extractions.json) so the pipeline runs end-to-end with
// 0 token spend. The REAL extractor (./claude.js) drops in behind the same signature.
import { readFileSync } from 'node:fs';

export function makeReplayExtractor(seedPath) {
  const seed = JSON.parse(readFileSync(seedPath, 'utf8'));
  const byIndex = new Map(seed.map((e) => [String(e.i).padStart(3, '0'), e]));

  const replay = async (source) => {
    const idx = source.id.replace(/\.md$/, '');
    const entry = byIndex.get(idx);
    if (!entry) {
      throw new Error(
        `replay: no seed extraction for ${source.id}. ` +
          `Wire a real extractor (src/extractors/claude.js) to process new sources.`
      );
    }
    // illustrative token cost: ~ input_chars/4 + a small output (matches the ~13k/interview note)
    const cost_tokens = Math.ceil(source.text.length / 4) + 800;
    return {
      model: 'replay-haiku',
      confidence: 0.9,
      persona: entry.persona ?? null,
      opportunities: entry.opps.map((o) => ({
        slug: o.slug,
        label: o.label,
        quote: o.quote || '',
        importance: o.importance,
        satisfaction: o.satisfaction,
      })),
      cost_tokens,
    };
  };
  return replay;
}
